// Parse weather data from API response
const weatherData = $input.item.json;

// Extract weather information
const city = weatherData.name;
const temperature = weatherData.main.temp;
const temperatureUnit = 'C';
const condition = weatherData.weather[0].description;
const humidity = weatherData.main.humidity;
const windSpeed = weatherData.wind.speed;

// Build formatted summary
const summary = `- Daily Weather - ${city}\n- Temp: ${temperature}°${temperatureUnit}\n- Condition: ${condition}\n- Humidity: ${humidity}%\n- Wind: ${windSpeed} km/h`;

// Determine alert type based on rules
let alertType = 'none';
const conditionLower = condition.toLowerCase();

if (conditionLower.includes('rain') || conditionLower.includes('snow') || 
    conditionLower.includes('drizzle') || conditionLower.includes('storm') || 
    conditionLower.includes('thunder')) {
  alertType = 'precipitation';
} else if (temperature >= 32) {
  alertType = 'heat';
} else if (temperature <= 0) {
  alertType = 'frost';
}

// Add alert message if applicable
let alertMessage = '';
if (alertType === 'precipitation') {
  alertMessage = 'Alert: Rain Expected Today';
} else if (alertType === 'heat') {
  alertMessage = 'Alert: Heat Warning';
} else if (alertType === 'frost') {
  alertMessage = 'Alert: Frost Warning';
}

const fullSummary = alertMessage ? `${summary}\n\n${alertMessage}` : summary;

// Return formatted data
return [{
  json: {
    city: city,
    temperature: temperature,
    temperatureUnit: temperatureUnit,
    condition: condition,
    humidity: humidity,
    windSpeed: windSpeed,
    alertType: alertType,
    summary: fullSummary,
    rawResponse: weatherData,
    runAt: new Date().toISOString()
  }
}];

// Define multiple cities to fetch weather for
const cities = ['London', 'New York', 'Tokyo', 'Paris', 'Sydney'];

// Return one item for each city
return cities.map(city => ({
  json: { city: city }
}));
